// Normalise payload from Procore OR Fieldwire OR simulated form
const body = $input.item.json.body ?? $input.item.json;

const issue = {
  id:          body.id          ?? body.issue_id       ?? body.record_id     ?? `SIM-${Date.now()}`,
  title:       body.title       ?? body.subject        ?? body.name          ?? 'Untitled Issue',
  description: body.description ?? body.body           ?? body.details       ?? '',
  location:    body.location    ?? body.area           ?? body.zone          ?? 'Unknown',
  reporter:    body.created_by  ?? body.reported_by    ?? body.submitter     ?? 'Unknown',
  assignee:    body.assignee    ?? body.assigned_to    ?? body.responsible   ?? '',
  source:      body.source      ?? body.tool           ?? 'Procore/Fieldwire',
  rawType:     body.type        ?? body.category       ?? body.issue_type    ?? '',
  receivedAt:  new Date().toISOString()
};

return [{ json: issue }];

values.content:
=You are a construction-site incident classifier. Given the following issue details, return ONLY a valid JSON object with no markdown, no explanation, no code fences.

Title: {{ $json.title }}
Description: {{ $json.description }}
Location: {{ $json.location }}
Reporter: {{ $json.reporter }}
Raw Category: {{ $json.rawType }}

Return this exact JSON structure:
{
  "issueType": "<one of: Safety | RFI | Quality | Punch | Delay | Equipment | Environmental | Other>",
  "urgency": "<one of: Critical | High | Medium | Low>",
  "summary": "<one concise sentence, max 120 chars>",
  "recommendedAction": "<one concise sentence on what to do next>",
  "tags": ["<tag1>", "<tag2>", "<tag3>"]
}

Rules:
- Safety incidents with injury risk or OSHA implications → urgency = Critical
- RFIs blocking work or critical path → urgency = High
- Keywords like: fatality, injury, collapse, fire, gas leak, electric shock → urgency = Critical
- Return ONLY the JSON object. No extra text.

parameters.jsCode:
const raw = $input.item.json.message?.content ?? $input.item.json.choices?.[0]?.message?.content ?? '{}';
let classification;
try {
  classification = JSON.parse(raw);
} catch(e) {
  // Attempt to extract JSON from any stray text
  const match = raw.match(/\{[\s\S]*\}/);
  classification = match ? JSON.parse(match[0]) : { issueType:'Other', urgency:'Low', summary: raw.slice(0,120), recommendedAction:'Review manually', tags:[] };
}

// Merge classification back with the normalised issue from node 3
// $('Normalise Payload') gives us the upstream data
const issue = $('Normalise Payload').item.json;

return [{ json: { ...issue, ...classification } }];

