parameters.jsCode:
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { digestText: '\u2705 No open incidents at this time. All clear!', count: 0 } }];
}

const rows = items.map(i => i.json);

// Group by urgency
const groups = { Critical: [], High: [], Medium: [], Low: [], Other: [] };
rows.forEach(r => {
  const u = r.Urgency ?? r.urgency ?? 'Other';
  (groups[u] ?? groups.Other).push(r);
});

const today = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

let text = '*\uD83D\uDCCB Daily Incident Digest - ' + today + '*\n*Total Open Items: ' + rows.length + '*\n\n';

const urgencyEmoji = { Critical:'\uD83D\uDEA8', High:'\u26A0\uFE0F', Medium:'\uD83D\uDD35', Low:'\u26AA', Other:'\u2753' };

for (const [urgency, issues] of Object.entries(groups)) {
  if (issues.length === 0) continue;
  const emoji = urgencyEmoji[urgency] || '\u2753';
  text += emoji + ' *' + urgency + ' (' + issues.length + ')*\n';
  issues.forEach(function(iss) {
    const id = iss.ID || iss.id || 'N/A';
    const title = iss.Title || iss.title || 'Untitled';
    const type = iss['Issue Type'] || iss.issueType || 'Unknown';
    const loc = iss.Location || iss.location || 'Unknown';
    const assignee = iss.Assignee || iss.assignee || 'Unassigned';
    text += '  - [' + id + '] ' + title + ' | ' + type + ' | ' + loc + ' | ' + assignee + '\n';
  });
  text += '\n';
}

text += '_Reply to any item in Slack or update status in Google Sheets._';

return [{ json: { digestText: text, count: rows.length } }];

